import java.util.ArrayList;
import java.util.List;

class Solution {
    public List<Integer> lexicalOrder(int n) {
        List<Integer> result = new ArrayList<>();
        for (int i = 1; i <= 9; i++) {
            generate(i, n, result);
        }
        return result;
    }

    private void generate(int current, int n, List<Integer> result) {
        if (current > n) {
            return;
        }
        result.add(current);
        for (int d = 0; d <= 9; d++) {
            generate(current * 10 + d, n, result);
        }
    }
}
